INSERT INTO public.photos VALUES (25807, 'San Miguel c.1895', 'Dibujo de "Saint-Michel des Navarrais" firmado por Boudier, como ilustraci├│n al parisino libro "Aragon et Valence, Barcelone, Saragosse, Sagonte, Valence : les beaux-arts, les moeurs, les coutumes", de Madame Jane Dieulafoy, editado en 1901. La imagen se corresponde con el estado de la torre parroquial antes de la intervenci├│n de 1898, en que se instal├│ un nuevo chapitel modernista dise├▒ado por Ricardo Magdalena. Fuente visual: gallica.bnf.fr/', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64958700, -0.87634200, '0101000020E6100000368FC360FE0AECBF1074B4AA25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24910482236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24910482236.webp', 'https://www.flickr.com/photos/zaragozaantigua/24910482236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25808, 'Calle San Miguel 1895', '"Vista perspectiva de la casa n┬║ 22 y parcela de la n┬║ 20 de la calle de San Miguel, contiguas al convento de Sta. Catalina, de la propiedad de D. F├®lix Burriel". Francisco de Paula Albi├▒ana, Zaragoza, 26 de noviembre de 1895. Detallado dibujo que muestra la esquina de la calle de San Miguel (izquierda) con la actual del Arquitecto Magdalena, entonces a├║n sin abrir. A la derecha, acceso al convento de monjas clarisas de Santa Catalina. Fuente: DARA/AHPZ.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65028900, -0.87892500, '0101000020E6100000AA6054522720ECBF6AF981AB3CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25215948766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25215948766.webp', 'https://www.flickr.com/photos/zaragozaantigua/25215948766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25810, 'San Miguel c.1897', '"Zaragoza. Iglesia de San Miguel". Postal editada por la Fototipia de Lucas Escol├í hacia 1900, si bien la imagen de la iglesia parroquial de San Miguel de los Navarros, capturada desde cierta altura en la plaza de San Miguel, es anterior a la reforma de 1898, en la que se instal├│ un nuevo chapitel modernista dise├▒ado por Ricardo Magdalena. Fuente visual: www.todocoleccion.net/', 1897, 1897, 1897, 'Siglo XIX', 'CENTRO', 41.64953700, -0.87617100, '0101000020E61000000684D6C39709ECBF5F45460724D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25398540990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25398540990.webp', 'https://www.flickr.com/photos/zaragozaantigua/25398540990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25811, 'Plaza de San Miguel c.1895', 'Captura fotogr├ífica de Marcel y Jane Dieulafoy de "Saragosse" incluida en el album "767 phot. d''Espagne, du Portugal et du Roussillon" editado en 1920, aunque con im├ígenes muy anteriores, como esta, correspondiente con la plaza de San Miguel, centrada en la iglesia parroquial antes de la intervenci├│n de Ricardo Magdalena en 1898. Fuente visual: gallica.bnf.fr/', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64953700, -0.87617100, '0101000020E61000000684D6C39709ECBF5F45460724D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29118294540.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29118294540.webp', 'https://www.flickr.com/photos/zaragozaantigua/29118294540/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25812, 'Calle Asalto 1995', 'Vista de la esquina de la calle Asalto con la del Hero├¡smo, en el proceso de derribo de sus inmuebles, luego ocupados por el bloque del n├║mero 23. Fuente: www.facebook.com/photo.php?fbid=1377347082278360&set=...', 1995, 1995, 1995, 'Anos 90', 'CENTRO', 41.64927900, -0.87479900, '0101000020E6100000255AF2785AFEEBBF637D03931BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30706986263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30706986263.webp', 'https://www.flickr.com/photos/zaragozaantigua/30706986263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25814, 'Calle del Asalto 1977', 'Imagen del primer tramo de la calle del Asalto que aqu├¡ incluye las traseras del n┬║ 2 de la calle de la Reconquista y los n├║meros 1 y 3 (en una vista parcial) de la del Asalto. A la izquierda, solar resultante del derribo del ruinoso inmueble que fuera n┬║ 10 de la plaza de San Miguel. Los carteles pegados a la derecha se corresponden con los tradicionales espect├ículos de las revistas que acud├¡an a la ciudad durante las fiestas del Pilar.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.64951400, -0.87591200, '0101000020E61000000491459A7807ECBFA725564623D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52437729024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52437729024.webp', 'https://www.flickr.com/photos/zaragozaantigua/52437729024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25900, 'Plaza de San Miguel c.1905', 'Imagen de la puerta del Duque de la Victoria se├▒alando el ingreso a la plaza de San Miguel desde la carretera de Zaragoza a Castell├│n, tal y como est├í a punto de hacer por su vano central uno de los "Primitivos" tranv├¡as de la l├¡nea del Bajo Arag├│n, electrificada recientemente. Al fondo, despu├®s de la calle de Espartero, el bloque de viviendas situado justo a la derecha del Almud├¡ y "las Piedras del Coso", eclipsadas de la visual por el se├▒or que cruza. Hac├¡a algunos a├▒os que se estaba dirimiendo el futuro de esta puerta, pues ten├¡a sus defensores, y sus detractores, sobre lo oportuno que era, o no, su mantenimiento. Unos a├▒os despu├®s de esta imagen (1911), el Ayuntamiento le amputar├¡a los dos peque├▒os ingresos laterales (parcialmente visible el de su izquierda), dejando el central. Finalmente, en abril de 1919 el gran arco central de la puerta fue tambi├®n desmantelado, y sus restos se volatilizaron. Fuente visual: "Las puertas de la ciudad", por Lasala, Serrano, y Torr├║s.', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.64948600, -0.87610900, '0101000020E61000008466D7BD1509ECBFDD9A745B22D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17683400330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17683400330.webp', 'https://www.flickr.com/photos/zaragozaantigua/17683400330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25930, 'Calle de Violante de Hungr├¡a 1954', 'Imagen capturada en el despejado principio de la calle de Violante de Hungr├¡a, un espacio que a├▒os m├ís tarde ser├¡a denominado plaza del Emperador Carlos de toda la vida, y centrada en la terminal tranviaria de la l├¡nea 11 &quot;Parque&quot; all├¡ ubicada, donde espera la unidad 209 para iniciar el descendente recorrido hasta la plaza de Espa├▒a. Tras la unificaci├│n con la l├¡nea 13 &quot;San Jos├®&quot; en 1967 esta unidad continu├│ realizando viajes hasta 1976, cuando la l├¡nea fue clausurada y la 209 desguazada. De fondo esc├®nico, a la izquierda uno de los pabellones del cuartel de Palafox recayente a la calle de Pedro Cerbuna, y a la derecha medianera y vista parcial del grupo de viviendas de la calle del Arzobispo Apaolaza 31-39, dise├▒ado por el arquitecto Antonio Ch├│liz Alcrudo dentro del desarrollo urban├¡stico del ensanche de Miralbueno. Fuente visual: Jos├® Mar├¡a Valero Su├írez, Centenario del tranv├¡a el├®ctrico. Zaragoza, 1902-2002.', 1954, 1954, 1954, 'Anos 50', 'UNIVERSIDAD', 41.63776300, -0.89858100, '0101000020E6100000BFD2F9F02CC1ECBFA7CCCD37A2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40480110120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40480110120.webp', 'https://www.flickr.com/photos/zaragozaantigua/40480110120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25905, 'Plaza de San Miguel 1968', 'Imagen con uno de esos zaragozanos d├¡as neblinosos en que los contornos de las cosas, a lo lejos, pierden consistencia, y se difuminan como los recuerdos. Tal que hoy. A la izquierda, al fondo, se intuye la g├│tico-mud├®jar torre, y el poligonal y cabecero ├íbside principal de la iglesia parroquial de San Miguel de los Navarros. Voladizo, el tendido el├®ctrico que garantizaba corriente continua de 600 voltios a las tranviarias l├¡neas de explotaci├│n que por aqu├¡ prestaban servicio. Hasta su desmantelamiento en 1966, lo hizo la l├¡nea 17 ("Las Fuentes"). Desde 1967, la nueva macrol├¡nea 11 "Parque-San Jos├®" (uni├│n de la 11 y la 13), adem├ís de la composici├│n 1 ("Bajo Arag├│n") + 15 ("Casablanca"), experimento que apenas durar├¡a un par de a├▒os. Entonces, la pionera l├¡nea del "Bajo Arag├│n" retomar├¡a su trazado, que comenz├│ all├í por 1885, llegando casi a cumplir los noventa a├▒os de servicio a la ciudad. Al final, todas fueron erradicadas para que los neum├íticos veh├¡culos que ruedan en la imagen, no fueran incordiados por esos malvados, medievales y molestos ingenios sobre ra├¡les, y bajo trole. Fuente: "Zaragoza Viva" (1969).', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64903200, -0.87583800, '0101000020E61000007102D369DD06ECBF5B07077B13D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24270528690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24270528690.webp', 'https://www.flickr.com/photos/zaragozaantigua/24270528690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25906, 'San Miguel c.1900', 'Imagen para postal de la Fototipia Hauser y Menet, de Madrid, capturando la iglesia de San Miguel de los Navarros, la Puerta del Duque de la Victoria, y una unidad de la tranviaria L├¡nea "Bajo Arag├│n" a punto de adentrarse en el tramo suburbano del recorrido, una vez cruzado el puente de San Jos├®, por la carretera de Zaragoza a Castell├│n, hasta la estaci├│n de ferrocarril de Cappa. Fuente visual: www.delcampe.es/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64903200, -0.87583800, '0101000020E61000007102D369DD06ECBF5B07077B13D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24293549684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24293549684.webp', 'https://www.flickr.com/photos/zaragozaantigua/24293549684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25909, 'Puerta del Duque c.1905', 'Vista de la iglesia de San Miguel y la Puerta del Duque desde el arranque del puente de San Jos├®. La unidad n┬║ 1 de la tranviaria y electrificada l├¡nea Bajo Arag├│n, rumbo a la estaci├│n de Cappa, o de Utrillas. Huecograbado de la serie "Arag├│n" de postales editadas por el librero Cecilio Gasca. Fuente visual: www.todocoleccion.net/', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.64953700, -0.87617100, '0101000020E61000000684D6C39709ECBF5F45460724D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26794889254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26794889254.webp', 'https://www.flickr.com/photos/zaragozaantigua/26794889254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25921, 'Pl. de San Miguel 1969', 'Imagen capturada durante el solsticio de verano (21 de junio) en la plaza de San Miguel, y centrada en la unidad n┬║ 302 de la tranviaria l├¡nea 11, encaminada hacia el barrio de San Jos├®. A la izquierda, antigua y monocroma fachada del n┬║ 12 de la plaza, antes de ser recrecido tres alturas m├ís. Tras el tranv├¡a, el n┬║ 14, que luego tambi├®n fue elevado una planta. A la derecha, la calle de Espartero, y el Coso. Este fue el ├║ltimo de los tranv├¡as hist├│ricos que circul├│ por Zaragoza en 1976, hasta que en 2011 fue recuperado este modo de transporte. Fuente visual: foto Mike Cornwall, en www.forotrenes.com/', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64981300, -0.87633000, '0101000020E6100000261E5036E50AECBF01C287122DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32230006414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32230006414.webp', 'https://www.flickr.com/photos/zaragozaantigua/32230006414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21847, 'Madre Sacramento 1934', 'Imagen capturada en el tramo inicial de la calle de la Venerable Madre Sacramento, de moderna urbanizaci├│n. A la izquierda, tras una amplia zona de huertos, anuncio comercial que se├▒ala la ubicaci├│n de los Talleres Mec├ínicos de Reparaci├│n de Autom├│viles Jos├® Iglesias. A la derecha, los antiguos inmuebles de los n├║meros 6, 8 y 10 de la calle, tras los que se abre la calle de la Industria, en cuya esquina destaca la moderna casa y f├íbrica de gaseosas de Hermenegildo Aguaviva, con dise├▒o de Regino Borobio. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.64937200, -0.89049200, '0101000020E61000002F302B14E97EECBF1478279F1ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35669809403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35669809403.webp', 'https://www.flickr.com/photos/zaragozaantigua/35669809403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22176, 'Madre Sacramento 1951', 'Despejada imagen de la calle Madre Sacramento capturada casi desde su ingreso por la calle de Hern├ín Cort├®s. A la izquierda, e inmediato, el edificio del n┬║ 5. A la derecha, el muro que delimitaba una antigua zona de huerta junto al convento de las MM. Adoratrices, y a continuaci├│n, el acceso a la calle del Capit├ín Esponera. Hacia el fondo, la calle avanza en curva hasta desembocar en Jos├® Anselmo Clav├®. Fuente visual: Foto Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64911600, -0.88978400, '0101000020E61000004B21904B1C79ECBFB9A7AB3B16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31558300655.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31558300655.webp', 'https://www.flickr.com/photos/zaragozaantigua/31558300655/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22208, 'P.┬║ de M┬¬ Agust├¡n c.1955', 'Imagen de la cl├¡nica de Nuestra Se├▒ora del Carmen de la que era titular el doctor Ricardo Horno Alcorta, sita en el paseo de Mar├¡a Agust├¡n n┬║ 23 (antiguo n┬║ 5 septuplicado), esquina con la antigua calle de la Industria (a la derecha, redenominada del Doctor Horno Alcorta tras su fallecimiento en 1948). A este edificio, en cuyas traseras se abr├¡a un notable jard├¡n interior, se le anex├│ a la inmediata izquierda en 1929 la casa de nueva planta del doctor Ricardo Horno, que hasta entonces residi├│ y ejerci├│ en la calle de Alfonso I, y que fue dise├▒ada por Fernando Garc├¡a Mercadal. Casa y cl├¡nica fueron m├ís tarde derribadas y en su solar fue construido un moderno y voluminoso bloque de viviendas. Fuente visual: "Mariano Horno Liria In Memoriam", La Cadiera, 2008.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65063100, -0.88965500, '0101000020E6100000D52137C30D78ECBFC36169E047D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41146665412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41146665412.webp', 'https://www.flickr.com/photos/zaragozaantigua/41146665412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22436, 'Paseo de Teruel 1965', 'Imagen capturada en el arranque del paseo de Teruel, cuando casualmente transita sobre el adoquinado pavimento el troleb├║s de dos pisos "BUT", dorsal n┬║ 72 de la l├¡nea "Ciudad Jard├¡n", entrado en servicio apenas un par de a├▒os antes, en su ruta hacia la terminal de la plaza de Santa Engracia. A su izquierda, la calle de Hern├ín Cort├®s, con el emboque a la calle de Castellv├¡, donde figuraba su antiguo y provinciano edificio esquinero. Al fondo, asoman las instalaciones del cuartel del ej├®rcito radicado donde estuviera el Convento de los Capuchinos. Detr├ís del troleb├║s, el chaflanero y reciente n┬║ 1 del paseo de Teruel, sede de la agencia urbana n┬║ 2 del local Banco Zaragozano (que dios guarde en su gloria). Fuente visual: Vicente Modesto Locual.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64863500, -0.88956900, '0101000020E6100000322251685977ECBF3E05C07806D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30548938871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30548938871.webp', 'https://www.flickr.com/photos/zaragozaantigua/30548938871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22495, 'Calle de la Madre Sacramento c.1961', 'Imagen capturada en el tramo de la calle de la Madre Sacramento entre las calles del Capit├ín Casado y la del Doctor Horno, antigua de la Industria, y centrada en el reci├®n construido inmueble del n┬║ 34. A su izquierda, el veterano edificio del n┬║ 36, y una vista parcial del antiguo n┬║ 38, derribado y sustituido por otro m├ís moderno al principio del siglo XXI. A su derecha, nave posiblemente de uso industrial que a├▒os despu├®s ser├¡a derribada para dar paso al desarrollista inmueble del n┬║ 32 de esta calle. En primer t├®rmino y a la izquierda, un isocarro de transporte y su operario.', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.64990700, -0.89178000, '0101000020E61000009A42E7357689ECBF82380F2730D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48232449977.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48232449977.webp', 'https://www.flickr.com/photos/zaragozaantigua/48232449977/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22578, 'Calle Castellv├¡ 1970', 'Calle de Castellv├¡ con el antiguo edificio de vivienda, almac├®n y portal├│n de su tramo final conducente a la calle de Hern├ín Cort├®s, luego sustituidos por dos modernos inmuebles. La toma se ha realizado desde la entrada a la estaci├│n de autobuses a Teruel, desde 2011 reutilizada por la contratista municipal de la limpieza. Al fondo destaca el edificio que hace chafl├ín con el paseo de Teruel, entonces ocupado como sucursal del Banco Zaragozano.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64832800, -0.88948400, '0101000020E6100000A5164A26A776ECBF618A7269FCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15547985537.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15547985537.webp', 'https://www.flickr.com/photos/zaragozaantigua/15547985537/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22743, 'Hern├ín Cort├®s 1973', 'Tramo de la calle de Hern├ín Cort├®s capturado junto al despartidero donde hacia la derecha da comienzo el paseo de Teruel, que muestra el acusado contraste entre los antiguos edificios de la zona, como el esquinero con la calle de Castellv├¡, e incluso el cuartel de Hern├ín Cort├®s, al fondo, con el bloque del n┬║ 23-25 en ejecuci├│n, que anuncia la nueva ortodoxia urban├¡stica de los tiempos: m├ís moderno, m├ís alto, m├ís descontextualizado.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64839400, -0.88960100, '0101000020E610000009A52F849C77ECBF19761893FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32122917224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32122917224.webp', 'https://www.flickr.com/photos/zaragozaantigua/32122917224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22798, 'Calle del Dr. Horno Alcorta 1975', 'Imagen capturada ante el n┬║ 18 de la adoquinada calle del Doctor Horno Alcorta, antigua de la Industria, que formaba parte de la vivienda y f├íbrica de gaseosas "El sif├│n higi├®nico" de Hermenegildo Aguaviva, dise├▒ada por Regino Borobio en 1929, y cuyo ingreso principal estaba radicado en la inmediata calle de la Madre Sacramento, a la izquierda de la escena. En primer t├®rmino, veterano cami├│n botellero de la empresa. Tras el cierre de la f├íbrica, la parte del inmueble correspondiente a la misma (el n┬║ 18 de la imagen) fue derribado y sobre su solar se construyeron modernos bloques de viviendas. Los bajos que aqu├¡ aparecen tambi├®n fueron luego notablemente transformados. En primer t├®rmino, veterano cami├│n botellero de la empresa, modelo Ford 1940.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64970100, -0.89079200, '0101000020E6100000D63A71395E81ECBFD996016729D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46395468091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46395468091.webp', 'https://www.flickr.com/photos/zaragozaantigua/46395468091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22869, 'Cuartel de Hern├ín Cort├®s a├▒os 80', 'Edificio del cuartel de Hern├ín Cort├®s, pr├│ximo a su demolici├│n, en los a├▒os 80 del siglo XX.', 1980, 1980, 1989, 'Anos 80', 'CENTRO', 41.64806300, -0.88999400, '0101000020E6100000F25B74B2D47AECBFB35F77BAF3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15769068735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15769068735.webp', 'https://www.flickr.com/photos/zaragozaantigua/15769068735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23053, 'Calle de Hern├ín Cort├®s 1994', 'Imagen capturada durante la construcci├│n del aparcamiento incluido en el gran proyecto de urbanizaci├│n del espacio antes ocupado por el cuartel de Hern├ín Cort├®s y que en 1977 el Ayuntamiento adquiri├│ por 209 millones de pesetas al ramo de la Guerra. Los 12.776 metros cuadrados de extensi├│n, que originalmente se hab├¡an calificado en el PGOU de 1968 como de "edificaci├│n intensiva", tras la recuperaci├│n de la democracia municipal dieron acogida a la Biblioteca de Arag├│n de titularidad auton├│mica, inaugurada en 1990, varios equipamientos municipales, como la Junta el Distrito Centro y el Centro de la Tercera Edad Francisco de Goya, el Residencial Hern├ín Cort├®s y una gran plaza que en 1996 ser├¡a denominada de Mariano Arregui Canela, en homenaje a este cantante de jota. En la escena y a la izquierda, traseras de los inmuebles del n┬║ 24-26 de la calle del Doctor Cerrada. A la derecha, tramo de la calle de Hern├ín Cort├®s entre la de Benito P├®rez Gald├│s y el despartidero donde arranca la calle del Carmen.', 1994, 1994, 1994, 'Anos 90', 'CENTRO', 41.64775900, -0.89012800, '0101000020E6100000DA1F28B7ED7BECBF475854C4E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50444890623.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50444890623.webp', 'https://www.flickr.com/photos/zaragozaantigua/50444890623/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23216, 'Calle Cortes de Arag├│n 2016', 'Septembrina y despejada imagen centrada en el no muy antiguo edificio de viviendas de planta triangular que conformaba el despartidero entre el arranque de las calles Cortes de Arag├│n (izquierda) y del Carmen (derecha). Abandonado desde finales del pasado siglo XX, en el momento de capturar esta imagen el edificio (propiedad de una entidad bancaria local) estaba ya abocado hacia el derribo integral para dejar paso a un moderno inmueble con 12 viviendas, garajes, trasteros y locales comerciales que se denominar├í "Edificio Puerta del Carmen". Fuente visual: foto Jos├® Mar├¡a Ballest├¡n Miguel.', 2016, 2016, 2016, 'Siglo XXI', 'CENTRO', 41.64743500, -0.89105300, '0101000020E61000000516C0948183ECBF94A46B26DFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41619085210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41619085210.webp', 'https://www.flickr.com/photos/zaragozaantigua/41619085210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23327, 'La Gemela del Buen Gusto 1876', '"Vista de La Gemela del Buen Gusto. F├íbrica de chocolate y dulces con motor de vapor de Eusebio Molins. Zaragoza", dibujo para anuncio, 1876. Esta f├íbrica, puesta en marcha en 1876, se hallaba en el n├║mero 228 del barrio del Castillo, direcci├│n correspondiente a la carretera de Zaragoza a Valencia, hoy paseo de Teruel. Fuente: M┬¬ Pilar Biel Ib├í├▒ez, Zaragoza y la industrializaci├│n: la arquitectura industrial 1875-1936, IFC, 2004.', 1876, 1876, 1876, 'Siglo XIX', 'CENTRO', 41.64839900, -0.89199600, '0101000020E6100000CA3505323B8BECBF2AE109BDFED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19176154254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19176154254.webp', 'https://www.flickr.com/photos/zaragozaantigua/19176154254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24038, 'Calle de Fita 1967', 'Imagen capturada en altura de una agrupaci├│n musical y art├¡stica ambulante, mientras escenificaba su actuaci├│n multidisciplinar ("performance") junto al portal del n┬║ 19 de la calle de Bernardo Fita. Metal, percusi├│n, y danza contempor├ínea, todo por unas pocas monedas ("crowdfunding"). El arte y los proyectos creativos y cooperativos ("coworking") est├ín en la calle desde hace tiempo. Mucho tiempo. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.64690100, -0.89097600, '0101000020E61000002EABB019E082ECBFF65FE7A6CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30145790852.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30145790852.webp', 'https://www.flickr.com/photos/zaragozaantigua/30145790852/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24263, 'Camino de los Cubos 1899', 'Imagen parcial del acceso principal a la f├íbrica de espejos La Veneciana, de Basilio Para├¡so, en el camino de los Cubos, junto a la fundici├│n de Pellicer y Juan (a la izquierda, fuera de plano), y con sus traseras mirando al Huerva al aire, en el paraje denominado"curva de La Veneciana" de ese r├¡o. Este edificio de 1897 posiblemente fue proyectado por F├®lix Navarro, y tras varios avatares. estuvo en funcionamiento hasta finales de los a├▒os 20 del novecientos, en que la f├íbrica fue reubicada en el barrio del Castillo. Fuente visual: foto Coyne, en "Arag├│n Ilustrado" n┬║ 2 (7 de enero de 1899).', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64608500, -0.88953700, '0101000020E61000005A9F724C1677ECBFD4B7CCE9B2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062656580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062656580.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062656580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24266, 'C.┬║ de los Cubos 1932', 'Imagen capturada en el tramo medio del camino de los Cubos, entre la calle de Fita, cuyo arranque queda a la izquierda, y la f├íbrica de materiales de precisi├│n geogr├ífica de Laguna de Rins. En primer plano, al aire, el brazal bajo de la acequia de la Romareda. Este escenario, en pleno centro de la ciudad, resultaba antiest├®tico, insalubre, y bien poco acorde con la categor├¡a socioecon├│mica de los propietarios de la zona, que no pod├¡an revalorizar adecuadamente los terrenitos de los aleda├▒os mientras el Ayuntamiento no urbanizara este vial. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.64655800, -0.88974100, '0101000020E610000079211D1EC278ECBFCC7B9C69C2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35752448555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35752448555.webp', 'https://www.flickr.com/photos/zaragozaantigua/35752448555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24434, 'Trinitarios Descalzos 1712', 'Localizaci├│n en el plano de Zaragoza de 1712 del convento de los Trinitarios descalzos en su ubicaci├│n junto al paseo de San Jer├│nimo o de la Ronda, el paseo de los Trinitarios y un brazal de la acequia de la Romareda.', 1712, 1712, 1712, 'Siglo XIX', 'CENTRO', 41.65103800, -0.89067500, '0101000020E610000071AC8BDB6880ECBF043A933655D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54388054248.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54388054248.webp', 'https://www.flickr.com/photos/zaragozaantigua/54388054248/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24484, 'Galletas La Universal c.1925', 'Lateral de una caja met├ílica de galletas "La Universal. Grandes Fabricantes de Galletas, Gaufrettes, Bizcochos", propiedad de Jos├® Mar├¡a Azanza y sita en la calle de Antonio C├ínovas 14 y 16, cuya f├íbrica se reproduce en el dibujo. A├▒os m├ís tarde, la f├íbrica continu├│ como propiedad de Doroteo As├¡n, hasta su derribo y conversi├│n en bloques de viviendas. Fuente visual: www.todocoleccion.net', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64810200, -0.89142700, '0101000020E61000003EAF78EA9186ECBF713C9F01F5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23644158804.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23644158804.webp', 'https://www.flickr.com/photos/zaragozaantigua/23644158804/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24533, 'Calle del Doctor Cerrada c.1950', 'Ins├│lita vista de la f├íbrica de Laguna de Rins inaugurada en 1880 en el camino de los Cubos. En la imagen, la factor├¡a aparece flanqueada en primer t├®rmino por el cuartel de Hern├ín Cort├®s, y por el inmueble del n┬║ 2 de la calle de Bernardo Fita. Al fondo, el esquinero inmueble del n┬║ 1 de esa calle. La estrecha calle del Doctor Cerrada mantiene alg├║n tramo al aire de la acequia de la Romareda, a la izquierda, junto a los muros perimetrales del gran recinto donde estuviera la f├íbrica de cristal de La Veneciana.', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.64672400, -0.88969900, '0101000020E6100000BE1589096A78ECBFE7C41EDAC7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49806577023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49806577023.webp', 'https://www.flickr.com/photos/zaragozaantigua/49806577023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25462, 'Cuartel de Hern├ín Cort├®s 1861', 'Cuartel de Hern├ín Cort├®s, al sur de la puerta del Carmen, junto al camino de Herederos. Imagen capturada desde la carretera de Valencia. Aqu├¡ estuvo el antiguo convento extramuros de San Juan Bautista de los PP. Capuchinos, destruido en 1808, desamortizado, y reedificado a mediados de siglo, en una parte del extenso per├¡metro conventual, ya como cuartel de infanter├¡a, tal y como sucedi├│ con otros antiguos conventos de la ciudad. Fuente visual: Mariano J├║dez y Ortiz. ├ülbum de Andr├®s Mart├¡n e Ip├ís. Colecci├│n Mariano Mart├¡n Casalderrey. Libro Primeros tiempos de la fotograf├¡a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64770700, -0.88982300, '0101000020E6100000C25087156E79ECBFF4311F10E8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710617658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710617658.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710617658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25474, 'Convento Capuchinos 1808', '"Prise du Couvent des Capucins". Versi├│n coloreada del dibujo de Karl Girardet grabado por Paul Girardet, incluido en "Histoire du Consulat et de l''Empire, faisant suite a l''Histoire de la R├®volution Fran├ºaise", de Adolphe Thiers, Paulin (Paris), 1845-1862. Representaci├│n de la toma por el ej├®rcito franc├®s del convento de los Capuchinos en julio de 1808. Este convento, dedicado a San Juan Bautista, fue construido en 1598, reedificado en 1830, desamortizado en 1835 y reutilizado como cuartel de infanter├¡a Hern├ín Cort├®s, en el n├║mero 33 de la actual calle hom├│nima, hoy plaza de Mariano Arregui y alrededores. Fuente visual: www.jeanlannes.com/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64772500, -0.89014000, '0101000020E6100000EB909BE1067CECBF9BE61DA7E8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27895969903.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27895969903.webp', 'https://www.flickr.com/photos/zaragozaantigua/27895969903/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25477, 'Calle Cortes de Arag├│n 1951', 'Imagen tomada desde la calle de Hern├ín Cort├®s (con su cuartel hom├│nimo a la izquierda). En el centro, edificio que hace chafl├ín entre las calles de las Cortes de Arag├│n (izquierda) y del Carmen (derecha). Fuente: Archivo Mora. Ayuntamiento de Zaragoza.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64743500, -0.89105300, '0101000020E61000000516C0948183ECBF94A46B26DFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29857214426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29857214426.webp', 'https://www.flickr.com/photos/zaragozaantigua/29857214426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20973, 'Santa Engracia 1808', '"Explosi├│n de la Iglesia de Sante Engracia en el d├¡a 4 de Agosto de 1808 de resultas de haberla minado los Franceses", Serie Ruinas de Zaragoza, de Juan G├ílvez (dibujo) y Fernando Brambila (grabado), C├ídiz, 1812. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64884800, -0.88284400, '0101000020E6100000CC086F0F4240ECBF9A0986730DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19364883560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19364883560.webp', 'https://www.flickr.com/photos/zaragozaantigua/19364883560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20982, 'Convento de Santa Engracia 1854', '"Ruinen des Klosters Santa Engracia (Saragofsa)", xilograf├¡a reproduciendo un grabado, Jugendfr, 1854. Fuente: AMZ.', 1854, 1854, 1854, 'Siglo XIX', 'CENTRO', 41.64880900, -0.88217800, '0101000020E6100000A305685BCD3AECBFDC2C5E2C0CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21019239776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21019239776.webp', 'https://www.flickr.com/photos/zaragozaantigua/21019239776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20987, 'Receptio animae 1890', '"Sarc├│fago de Santa Engracia en Zaragoza. Tomado al natural por Anselmo Gasc├│n de Gotor". Dibujo de uno de los dos sarc├│fagos paleocristianos del siglo IV presentes en la cripta de las Santas Masas de la iglesia de Santa Engracia. ├ëste es el denominado "Receptio animae". debido a que en su centro aparece una figura femenina cuya mano es agarrada por otra que surge de arriba. Fuente: "Revue de l''art chr├®tien", a trav├®s de www.flickr.com/photos/internetarchivebookimages/14773440465/', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64884800, -0.88284400, '0101000020E6100000CC086F0F4240ECBF9A0986730DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24545171524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24545171524.webp', 'https://www.flickr.com/photos/zaragozaantigua/24545171524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21017, 'Puerta de Santa Engracia 1860', '"Arco del triunfo erigido en la puerta de Santa Engracia (Zaragoza)". Mientras se estaba tratando de convertir la Puerta de Santa Engracia en un arco de triunfo, el anuncio de la visita de la reina Isabel II oblig├│ a recurrir a la simulaci├│n de lienzos pintados encima para dar la apariencia de lo que no hab├¡a. As├¡, en la imagen, la puerta-trampantoja vista desde el Sal├│n de Santa Engracia, con visual por el vano central de la reciente estatua a Ram├│n Pignatelli en la Glorieta de su nombre. Este grabado apareci├│ en la revista "El Museo Universal" en su n├║mero 49 (02-XII-1860). En la p├ígina del Ministerio de Cultura en la que se encuentra, est├í incorrectamente datada como "n┬║ 42 (14-X-1860)", ya que fue en ese n├║mero en el que se public├│ la breve rese├▒a de su paso por Zaragoza el 7 de octubre de ese a├▒o, aunque las ilustraciones, tanto esta de la Puerta de Santa Engracia, como la del "Templete levantado en la Calle del Coso", aparecieron luego en el n├║mero rese├▒ado de diciembre. Fuente visual: www.mecd.gob.es/', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64900800, -0.88419600, '0101000020E6100000E620E868554BECBFD36BB3B112D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19459028853.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19459028853.webp', 'https://www.flickr.com/photos/zaragozaantigua/19459028853/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21018, 'Santa Engracia 1867', '"Ruinas de la iglesia de Santa Engracia", xilograf├¡a de Tom├ís Carlos Capuz incluida en la Cr├│nica general de Espa├▒a, Madrid, 1867. Portada de la iglesia de Santa Engracia de Zaragoza antes de su restauraci├│n en 1899. Se observa la torre desmochada en 1809 y el Cuartel de Infanter├¡a anexo.', 1867, 1867, 1867, 'Siglo XIX', 'CENTRO', 41.64908500, -0.88268800, '0101000020E6100000F14A92E7FA3EECBF7EA99F3715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19527548182.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19527548182.webp', 'https://www.flickr.com/photos/zaragozaantigua/19527548182/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21026, 'Santa Engracia 1860', '"Zaragoza: fachada principal de Santa Engracia", fotograf├¡a capturada durante la visita oficial de la reina Isabel II a la ciudad. Frente a la fachada de la iglesia del antiguo Real monasterio, restos de la vegetal ornamentaci├│n impostada para engalanar la ocasi├│n, adem├ís de la habitual garita de guardia del inmediato cuartel de Santa Engracia (a la izquierda, fuera de plano). Fuente: Charles Clifford , en Biblioteca Nacional de Espa├▒a', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64906300, -0.88288500, '0101000020E61000007120240B9840ECBF9605137F14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22427135050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22427135050.webp', 'https://www.flickr.com/photos/zaragozaantigua/22427135050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21044, 'Puerta de Santa Engracia 1860', 'Dibujo firmado por el arquitecto Federico Inguenza Castellanos que result├│ ganador del concurso nacional convocado en 1859 para finalizar la Puerta de Santa Engracia iniciada en 1830 e inacabada desde entonces. Se trata de una simbiosis entre la funcional puerta y un monumento a la memoria de los "h├®roes" de 1808-1809, aunque este proyecto tampoco transit├│ la frontera entre las musas y el teatro, y cuando la reina Isabel II visit├│ Zaragoza ese a├▒o se hubo de cubrir con lienzos pintados a modo de trampantojo para simular que estaba terminada. Finalmente, en 1865 se demoli├│ la estructura inacabada de esta "segunda" Puerta de santa Engracia.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64894200, -0.88433500, '0101000020E61000003FA9F6E9784CECBF1B800D8810D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52255522959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52255522959.webp', 'https://www.flickr.com/photos/zaragozaantigua/52255522959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21067, 'Plaza de Santa Engracia  c.1878', '"Fachada de la Iglesia de Santa Engracia". Imagen de la plaza de Santa Engracia. A la izquierda, el Cuartel de Infanter├¡a de Santa Engracia, adosado a la portada de la Iglesia del mismo nombre. A la derecha, muro y acceso a la cripta del pozo de las reliquias. Al fondo, sobresalen ├írboles del Paseo de la Mina. Fuera de plano, justo al lado y hacia la derecha, ese mismo a├▒o de 1878 ser├í inaugurado el Teatro Pignatelli. A la espalda del fot├│grafo, la manzana de viviendas que alberg├│, en el palacete del bar├│n de la Rosa, la Capitan├¡a General de la Regi├│n Militar desde 1867 a 1888, en su ├║ltima ubicaci├│n itinerante antes de recaer definitivamente en el edificio de la Glorieta de Pignatelli. Entre 1891 y 1899, Mariano L├│pez le dar├¡a un nuevo aire a la iglesia de Santa Engracia, incluyendo la torre que falta en la imagen. El Cuartel de Santa Engracia ser├¡a piqueteado en 1906, y parte de sus terrenos formar├¡an parte del recinto ferial de la Expo 1908. Fuente visual: Archivo Ruiz Vernacci, Foto: Jean Laurent. 1863-1880.', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.64908500, -0.88268800, '0101000020E6100000F14A92E7FA3EECBF7EA99F3715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17081234980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17081234980.webp', 'https://www.flickr.com/photos/zaragozaantigua/17081234980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21095, 'Plaza de Santa Engracia 1889', 'Imagen tomada en la plaza de Santa Engracia y centrada en la fachada de la iglesia hom├│nima, a cuya izquierda queda adosado el conjunto de edificaciones que formaban parte del cuartel tambi├®n denominado de Santa Engracia y que acog├¡a el regimiento de infanter├¡a "Arag├│n" n┬║ 21.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64910600, -0.88288600, '0101000020E6100000871403249A40ECBF96D1C8E715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14772661529.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14772661529.webp', 'https://www.flickr.com/photos/zaragozaantigua/14772661529/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21106, 'Santa Engracia 1889', '"Saragosse. Ruines de l''ancien convent de Santa Engracia". Fuente: J. L├®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Arag├│n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64906300, -0.88288500, '0101000020E61000007120240B9840ECBF9605137F14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22104753273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22104753273.webp', 'https://www.flickr.com/photos/zaragozaantigua/22104753273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21119, 'Teatro Pignatelli 1880', 'Imagen del interior del Teatro Pignatelli, esquinero entre la calle de la Independencia y la plaza de Santa Engracia, construido como teatro de verano en materiales potencialmente poco duraderos, aunque alcanz├│ los cuarenta a├▒os de servicio. Fue as├¡ denominado por la influencia de la cercana estatua a Ram├│n Pignatelli que presid├¡a la glorieta que se abr├¡a en el ├║ltimo tramo de la calle de la Independencia. El escenario, al fondo, estaba orientado hacia el suroeste. Fuente visual: Foto Estudio Coyne, AHPZ.', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.64914000, -0.88337800, '0101000020E61000003C3080F0A144ECBF4243FF0417D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30862758614.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30862758614.webp', 'https://www.flickr.com/photos/zaragozaantigua/30862758614/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21122, 'Calle de la Independencia 1880', 'Imagen del Teatro de Pignatelli, construido en 1878 bajo la direcci├│n del arquitecto F├®lix Navarro. La captura fotogr├ífica ha sido realizada desde cierta altura, lo que permite una interesante visual, en primer t├®rmino, del andador central de la calle de la Independencia, arbolada y con bancos, y luego de las escalerillas por las que bajar desde esa calle hasta la plaza de Santa Engracia, a la izquierda. Unas leves vallas atemperan posibles riesgos de ca├¡das a distinto nivel. Al fondo, a la derecha, el colegio del Salvador, al otro lado del r├¡o Huerva. Fuente visual: Foto Venancio Villas Langa, AHPZ.', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.64914000, -0.88337800, '0101000020E61000003C3080F0A144ECBF4243FF0417D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31588067501.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31588067501.webp', 'https://www.flickr.com/photos/zaragozaantigua/31588067501/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21147, 'Jardinera veloz en Independencia c.1890', 'La imagen se corresponde con una de las cinco unidades "jardinera" del cuarto ramal del tranv├¡a (Torrero), inaugurado en 1886, con salida en el Sal├│n de Santa Engracia (luego calle de la Independencia , y despu├®s Paseo) junto a la calle C├ídiz, hasta la Playa de Torrero (hoy Barrio San Jos├®). Circula en direcci├│n a Torrero en la confluencia del Sal├│n de Santa Engracia con un vial que en 1923 recibir├í el nombre de "Albareda". El edificio de viviendas de la derecha, en cuyos bajos estaba el "Caf├® Ambos Mundos", susbiste modificado por una reforma de 1928. El edificio de la izquierda era uno de los hotelitos del entorno de la Glorieta de Pignatelli (luego Plaza de Arag├│n). Ser├í piqueteado a finales del siglo XX. "Veloz Sport" era la denominaci├│n de uno de los clubs velocip├®dicos de la ciudad, adem├ís de la "Sociedad de Velocipedistas de Zaragoza" (en su sede del Paseo de la Lealtad, luego de Pamplona).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64901700, -0.88447400, '0101000020E61000009831056B9C4DECBF26C632FD12D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15233478180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15233478180.webp', 'https://www.flickr.com/photos/zaragozaantigua/15233478180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21153, 'Calle Independencia ca. 1899', 'Cruza la calle de la Independencia un desfile militar proveniente del Parque de Ingenieros, y marcha al Cuartel de Santa Engracia por la calle de Bruil y la de Ronda. El abanderado, como im├ín de criaturas inconscientes. A la derecha, el antiguo palacete del bar├│n de la Rosa, que fuera en parte sede de la Capitan├¡a General de 1867 a 1888, y el enorme Teatro Pignatelli. Ambos edificios conformaban, por aquel entonces, buena parte de la plaza de Santa Engracia. Fuente visual: Archivo familiar G├│mez Laguna, en "El libro de oro de Arag├│n", EPA, 1997.', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64882000, -0.88410200, '0101000020E61000008D800A47904AECBFD07EA4880CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18762759084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18762759084.webp', 'https://www.flickr.com/photos/zaragozaantigua/18762759084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21168, 'Calle de la Independencia 1898', 'Un grupo de ciclistas pasa ante el Teatro Pignatelli sito en la calle de la Independencia. Tras la bajada a la plaza de Santa Engracia, la gran casa del conde de la Rosa, provisional sede de la Capitan├¡a General entre 1867 y 1888. Sobre el firme, v├¡as de la l├¡nea de Torrero. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1898, 1898, 1898, 'Siglo XIX', 'CENTRO', 41.64923900, -0.88363700, '0101000020E61000003E23111AC146ECBFD52478431AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25568250998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25568250998.webp', 'https://www.flickr.com/photos/zaragozaantigua/25568250998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21220, 'Santa Engracia 1903', 'Foto Pierre Petit 1903. Portada de la iglesia de Santa Engracia de Zaragoza en 1903. A su derecha, valla del cuartel anexo hom├│nimo, al cual pertenence la garita de la izquierda. Fuente: www.facebook.com/photo.php?fbid=848966978459262&set=o...', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64908500, -0.88268800, '0101000020E6100000F14A92E7FA3EECBF7EA99F3715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15879988936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15879988936.webp', 'https://www.flickr.com/photos/zaragozaantigua/15879988936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21239, 'Exposici├│n Hispano Francesa 1908', 'Foto: Ignacio Coyne, 1908. Panorama de la Exposici├│n Hispano Francesa de Zaragoza, vista desde la entrada. A la izquierda y derecha, flanquean el este espacio los gemelos pabellones de Tracci├│n y Maquinaria. Al fondo, ante el despliegue de las torres de Zaragoza, el Pabell├│n de la Alimentaci├│n. Fuente: ├ülbum oficial de la Exposici├│n Hispano-Francesa, 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64876200, -0.87993100, '0101000020E61000000892770E6528ECBF9B711AA20AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19615141205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19615141205.webp', 'https://www.flickr.com/photos/zaragozaantigua/19615141205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
